external_knowledge:
- Significant volumes refer to trades exceeding 1,000,000 shares;
- The dawn of 2020 refers to the date after January 1, 2020;
- Trading waves metaphorically refer to the volume of shares traded;
- The forecasted lowest opening prices refer to the minimum opening prices of future trades for each company.

sql:
SELECT AVG(performance) AS average_sector_performance
FROM sector_performance
WHERE strftime('%Y', date) = '2020';

SELECT name, sector
FROM companies
WHERE sector = 'Utilities';

SELECT COUNT(*)
FROM news_articles
WHERE company_id = (SELECT company_id FROM companies WHERE symbol = 'FE');

SELECT c.name, c.industry, al.access_type
FROM companies c
INNER JOIN access_logs al ON c.company_id = al.company_id
WHERE al.access_date = (
    SELECT MAX(access_date) FROM access_logs
);

SELECT sector
FROM companies
WHERE symbol = 'FE';

